import React, { useEffect, useCallback } from "react";
import { StyleSheet, View, Text, TouchableOpacity } from "react-native";
import { NavigationContainer } from "@react-navigation/native";
import { GestureHandlerRootView } from "react-native-gesture-handler";
import { KeyboardProvider } from "react-native-keyboard-controller";
import { SafeAreaProvider } from "react-native-safe-area-context";
import { StatusBar } from "expo-status-bar";
import * as SplashScreen from "expo-splash-screen";
import { Ionicons } from "@expo/vector-icons";

import RootNavigator from "@/navigation/RootNavigator";
import { ErrorBoundary } from "@/components/ErrorBoundary";
import { AuthProvider, useAuth } from "@/hooks/useAuth";
import { ThemeProvider, useTheme } from "@/hooks/useTheme";
import { LanguageProvider, useLanguage } from "@/hooks/useLanguage";
import IncomingCallHandler from "@/components/IncomingCallHandler";
import { registerForPushNotificationsAsync, setupNotificationListeners } from "@/services/notifications";
import { getApiBaseUrl } from "@/constants/config";

SplashScreen.preventAutoHideAsync();

// Print API configuration on startup
console.log('\n\n========== AFROCONNECT APP STARTED ==========');
console.log('🌐 API Base URL:', getApiBaseUrl());
console.log('📝 Signup URL:', `${getApiBaseUrl()}/api/auth/signup`);
console.log('🔐 Login URL:', `${getApiBaseUrl()}/api/auth/login`);
console.log('==========================================\n\n');

function LanguageSync() {
  const { user, isLoading } = useAuth();
  const { syncFromProfile, resetLanguage } = useLanguage();

  useEffect(() => {
    if (!isLoading) {
      if (user?.id && user?.preferences?.language) {
        syncFromProfile(user.preferences.language, user.id);
      } else if (!user) {
        resetLanguage();
      }
    }
  }, [isLoading, user?.id, user?.preferences?.language, syncFromProfile, resetLanguage, user]);

  return null;
}

function AppContent() {
  const { isDark } = useTheme();
  const { user } = useAuth();
  const [isOverlayVisible, setIsOverlayVisible] = React.useState(false);

  const onLayoutRootView = useCallback(async () => {
    await SplashScreen.hideAsync();
  }, []);

  // Initialize notifications when user is authenticated
  useEffect(() => {
    if (!user?.id) return;

    let unsubscribe: (() => void) | undefined;

    const setupNotifications = async () => {
      try {
        // Register for push notifications
        await registerForPushNotificationsAsync();

        // Setup listeners for incoming notifications
        unsubscribe = setupNotificationListeners(
          (notification) => {
            console.log('Notification received:', notification);
            // Handle notification when app is in foreground
          },
          (response) => {
            console.log('User tapped notification:', response);
            // Handle user tapping on notification
          }
        );
      } catch (error) {
        console.error('Failed to setup notifications:', error);
      }
    };

    setupNotifications();

    return () => {
      if (unsubscribe) unsubscribe();
    };
  }, [user?.id]);

  useEffect(() => {
    onLayoutRootView();
  }, [onLayoutRootView]);

  return (
    <GestureHandlerRootView style={styles.root} onLayout={onLayoutRootView}>
      <KeyboardProvider>
        <NavigationContainer>
          <RootNavigator />
          <IncomingCallHandler />
        </NavigationContainer>
        <StatusBar style={isDark ? "light" : "dark"} />

        {/* Toggle Button for Overlay */}
        <TouchableOpacity 
          style={styles.toggleButton} 
          onPress={() => setIsOverlayVisible(!isOverlayVisible)}
        >
          <Ionicons name={isOverlayVisible ? "eye-off" : "eye"} size={24} color="#fff" />
        </TouchableOpacity>

        {/* Global Overlay */}
        {isOverlayVisible && (
          <View style={[styles.overlay, { backgroundColor: isDark ? 'rgba(0,0,0,0.9)' : 'rgba(255,255,255,0.9)' }]}>
            <Text style={[styles.overlayText, { color: isDark ? '#fff' : '#000' }]}>
              {isDark ? "Night Mode Active" : "Day Mode Active"}
            </Text>
            <TouchableOpacity 
              style={styles.closeButton} 
              onPress={() => setIsOverlayVisible(false)}
            >
              <Text style={styles.closeButtonText}>Close Overlay</Text>
            </TouchableOpacity>
          </View>
        )}
      </KeyboardProvider>
    </GestureHandlerRootView>
  );
}

export default function App() {
  return (
    <ErrorBoundary>
      <SafeAreaProvider>
        <ThemeProvider>
          <LanguageProvider>
            <AuthProvider>
              <LanguageSync />
              <AppContent />
            </AuthProvider>
          </LanguageProvider>
        </ThemeProvider>
      </SafeAreaProvider>
    </ErrorBoundary>
  );
}

const styles = StyleSheet.create({
  root: {
    flex: 1,
  },
  toggleButton: {
    position: 'absolute',
    bottom: 30,
    right: 30,
    backgroundColor: '#3b82f6',
    width: 50,
    height: 50,
    borderRadius: 25,
    justifyContent: 'center',
    alignItems: 'center',
    elevation: 5,
    zIndex: 9999,
  },
  overlay: {
    ...StyleSheet.absoluteFillObject,
    zIndex: 9998,
    justifyContent: 'center',
    alignItems: 'center',
  },
  overlayText: {
    fontSize: 24,
    fontWeight: 'bold',
    marginBottom: 20,
  },
  closeButton: {
    backgroundColor: '#3b82f6',
    paddingHorizontal: 20,
    paddingVertical: 10,
    borderRadius: 8,
  },
  closeButtonText: {
    color: '#fff',
    fontWeight: '600',
  }
});
